<span class="line"><span style="color:#F97583;">let</span><span style="color:#E1E4E8;"> proxyObj </span><span style="color:#F97583;">=</span><span style="color:#F97583;"> new</span><span style="color:#B392F0;"> Proxy</span><span style="color:#E1E4E8;">(target, handler);</span></span>
